message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a graph embedding/layout problem where colors are nodes and adjacencies are edges. To maximize empty cells, we need to find the smallest possible layout that preserves the adjacency graph and connectivity.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to extract the adjacency graph of the colors 1 to M. Identify which colors are adjacent to which other colors. Also, check if any color has internal connectivity constraints that require more than one cell (though the problem implies colors are sets of cells, the goal is to represent the color as a single connected component). Output a list of edges representing the color adjacency graph."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given a graph of M nodes and their adjacency requirements, find a way to embed these nodes into a 50x50 grid such that each node is represented by at least one cell, all nodes are connected to their neighbors, and the total number of cells used is minimized. The output should be a 50x50 grid where each cell contains the color ID or 0 for empty."
    }
  ],
  "synthesis_brief": "Use the adjacency graph from the first helper to guide the second helper in creating a compact grid layout. The final output must be the 50x50 grid produced by the layout optimizer."
}

